393	json common_chat_msgs_to_json_oaicompat(const std::vector<common_chat_msg> & msgs, bool concat_typed_text) {
394	    jinja::caps c;
395	    c.supports_string_content = true;
396	    c.supports_typed_content = !concat_typed_text;
397	    return render_message_to_json(msgs, c);
