// Handler for Mistral Instruct v0.3 format (e.g. Mistral-Nemo-Instruct-2407).
// Format:
//   - User turns:      [INST]{content}[/INST]
//   - System message:  prepended to first user turn by the Jinja template
//   - Assistant turns: {content}</s>
//   - Tool calls:      [TOOL_CALLS][{"name":…,"arguments":{…},"id":"…"},…]</s>
static common_chat_params common_chat_params_init_mistral_instruct_v3(
        const common_chat_template &          tmpl,
        const autoparser::generation_params & inputs) {
    common_chat_params data;

    const auto has_tools     = inputs.tools.is_array() && !inputs.tools.empty();
    const auto include_tools = has_tools && inputs.tool_choice != COMMON_CHAT_TOOL_CHOICE_NONE;

    data.prompt           = common_chat_template_direct_apply_impl(tmpl, inputs);
    data.format           = COMMON_CHAT_FORMAT_PEG_NATIVE;
    data.preserved_tokens = { "[TOOL_CALLS]" };

    auto parser = build_chat_peg_parser([&](common_chat_peg_builder & p) {
        if (include_tools) {
            // Tool-call section: [TOOL_CALLS][{"name":…,"arguments":{…},"id":"…"},…]
            // array_wrapped=true because the list is enclosed in JSON array brackets.
            // parameters_order matches the emission order in the Jinja template.
            auto tool_calls = p.trigger_rule(
                "tool-call",
                p.standard_json_tools(
                    "[TOOL_CALLS]", "",
                    inputs.tools, inputs.parallel_tool_calls,
                    inputs.tool_choice == COMMON_CHAT_TOOL_CHOICE_REQUIRED,
                    "name", "arguments",
                    /* array_wrapped    = */ true,
                    /* function_is_key  = */ false,
                    /* call_id_key      = */ "id",
                    /* gen_call_id_key  = */ "",
                    /* parameters_order = */ { "name", "arguments", "id" }
                )
            );
            return p.literal(inputs.generation_prompt) +
                   p.content(p.until("[TOOL_CALLS]")) +
                   tool_calls;
        }

        // Content-only response
        return p.literal(inputs.generation_prompt) + p.content(p.rest());
    });

    data.parser = parser.save();

    if (include_tools) {
        data.grammar_lazy = inputs.tool_choice == COMMON_CHAT_TOOL_CHOICE_AUTO;
        data.grammar      = build_grammar([&](const common_grammar_builder & builder) {
            foreach_function(inputs.tools, [&](const json & tool) {
                const auto & function = tool.at("function");
                auto         schema   = function.at("parameters");
                builder.resolve_refs(schema);
            });
            parser.build_grammar(builder, data.grammar_lazy);
        });
        data.grammar_triggers = {
            { COMMON_GRAMMAR_TRIGGER_TYPE_WORD, "[TOOL_CALLS]" }
        };
    }

    return data;
}

namespace workaround {

static void map_developer_role_to_system(json & messages) {
    for (auto & message : messages) {
        if (message.contains("role")) {
            if (message["role"] == "developer") {
                message["role"] = "system";
            }
